import sys

def count_similar_pairs(n, d, a):
    count = 0
    a.sort()
    for i in range(n):
        left, right = i + 1, n
        while left < right:
            mid = (left + right) // 2
            if a[mid] - a[i] <= d:
                left = mid + 1
            else:
                right = mid
        count += left - i - 1
    return count

