from collections import defaultdict

def count_similar_pairs(n, d, a):
    count = 0
    value_counts = defaultdict(int)
    for num in a:
        value_counts[num] += 1

    for num, freq in value_counts.items():
        if freq > 1:
            count += freq * (freq - 1) // 2
        for offset in range(1, d + 1):
            if num + offset in value_counts:
                count += freq * value_counts[num + offset]
            if num - offset in value_counts and num - offset != num:
                count += freq * value_counts[num - offset]

    # Avoid double counting
    for num, freq in value_counts.items():
        if freq > 1:
            count -= freq * (freq - 1) // 2
        for offset in range(1, d + 1):
            if num + offset in value_counts:
                count -= freq * value_counts[num + offset]
            if num - offset in value_counts and num - offset != num:
                count -= freq * value_counts[num - offset]

    return count

