    return list(map(int, sys.stdin.readline().split()))

def main():
    n = int(sys.stdin.readline())
    a = read_ints()
    max_diff = 0
    for i in range(n):
        for j in range(i, n):
            if a[i] <= a[j]:
                max_diff = max(max_diff, j - i)
    print(max_diff)

if __name__ == "__main__":
    main()
```

