# Calculate prefix sums to speed up the calculation of block sums
prefix_sums = [0] * (n + 1)
for i in range(n):
    prefix_sums[i + 1] = prefix_sums[i] + a[i]

# Use binary search to find the longest light block ending at each position
count = 0
for i in range(n):
    left, right = i, n - 1
    while left <= right:
        mid = (left + right) // 2
        block_sum = prefix_sums[mid + 1] - prefix_sums[i]
        if block_sum <= s:
            left = mid + 1
        else:
            right = mid - 1
    count += left - i

