import sys

def count_light_blocks(N, S, A):
    count = 0
    for i in range(N):
        window_sum = 0
        for j in range(i, N):
            window_sum += A[j]
            if window_sum <= S:
                count += 1
            else:
                break
    return count

N, S = map(int, sys.stdin.readline().split())
A = list(map(int, sys.stdin.readline().split()))

# Use a more efficient approach
def atMost(S, A):
    if not A:
        return 0

    count = 0
    left = 0
    current_sum = 0

    for right in range(len(A)):
        current_sum += A[right]

        while current_sum > S and left <= right:
            current_sum -= A[left]
            left += 1

        count += right - left + 1

    return count

print(atMost(S, A))
