import sys

def main():
    n = int(sys.stdin.readline().strip())
    A = list(map(int, sys.stdin.readline().strip().split()))
    stack = []
    total_sum = 0
    for i in range(n):
        while stack and A[stack[-1]] >= A[i]:
            stack.pop()
        if stack:
            total_sum += A[stack[-1]]
        else:
            total_sum += -1
        stack.append(i)
    print(total_sum)

if __name__ == "__main__":
    main()
```

